import { Container } from 'inversify';
import { TYPES } from './types';
import { IRenderer } from './interfaces/IRenderer';
import { IPhysics } from './interfaces/IPhysics';
import { ISoundSystem } from './interfaces/ISoundSystem';

const container = new Container();
container.bind<IRenderer>(TYPES.Renderer).to(GLRenderer);
container.bind<IPhysics>(TYPES.Physics).to(QuakePhysics);
container.bind<ISoundSystem>(TYPES.Sound).to(SoundSystem);

export { container };
